SELECT to_char(('2018-06-01'::date + ((n || ' months'::text))::interval), 'YYYY/MM'::text) AS "年月"
  FROM generate_series(0, 99) t(n)
 WHERE (('2018-06-01'::date + ((n || ' months'::text))::interval) <= ((date_trunc('month'::text, (CURRENT_DATE)::timestamp with time zone) + '1 mon'::interval) - '1 day'::interval));
